def normalize_names(names):
    result = []
    for name in names:
        cleaned = name.strip()
        result.append(cleaned.title())
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_mixed_cases(self):
        self.assertEqual(
            normalize_names(["JOHN DOE", "jane smith", "aLiCe BoB"]),
            ["John Doe", "Jane Smith", "Alice Bob"]
        )

    def test_single_upper(self):
        self.assertEqual(normalize_names(["MARY"]), ["Mary"])

    def test_empty_list(self):
        self.assertEqual(normalize_names([]), [])

    def test_hidden_whitespace_stripping(self):
        self.assertEqual(
            normalize_names(["  hello world  "]),
            ["Hello World"]
        )

    def test_hidden_already_title_case(self):
        self.assertEqual(
            normalize_names(["Already Title Case"]),
            ["Already Title Case"]
        )

    def test_hidden_three_word_name(self):
        self.assertEqual(
            normalize_names(["MARY JANE WATSON"]),
            ["Mary Jane Watson"]
        )

    def test_hidden_single_character(self):
        self.assertEqual(normalize_names(["a"]), ["A"])

    def test_hidden_multiple_whitespace_names(self):
        self.assertEqual(
            normalize_names(["  UPPER  ", "  lower  ", "  mIxEd  "]),
            ["Upper", "Lower", "Mixed"]
        )

if __name__ == '__main__':
    unittest.main()
